output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?conflict ?conflictLabel ?goal ?goalLabel ?result ?resultLabel WHERE {
  ?conflict wdt:P710 wd:Q810 .
  ?conflict wdt:P3311 ?goal .
  OPTIONAL {
    ?conflict rdfs:label ?conflictLabel
    FILTER(LANG(?conflictLabel) = "en")
  }
  OPTIONAL {
    ?goal rdfs:label ?goalLabel
    FILTER(LANG(?goalLabel) = "en")
  }
  OPTIONAL {
    ?conflict wdt:P1500 ?result .
    OPTIONAL {
      ?result rdfs:label ?resultLabel
      FILTER(LANG(?resultLabel) = "en")
    }
  }
}
ORDER BY ?conflict

args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?conflict ?conflictLabel ?goal ?goalLabel ?result ?resultLabel
WHERE {
  ?conflict wdt:P710 wd:Q810.  # Jordan as participant
  ?conflict wdt:P3311 ?goal.    # Military objectives
  OPTIONAL { ?conflict rdfs:label ?conflictLabel FILTER(LANG(?conflictLabel) = "en") }
  OPTIONAL { ?goal rdfs:label ?goalLabel FILTER(LANG(?goalLabel) = "en") }
  OPTIONAL {
    ?conflict wdt:P1500 ?result.  # Result of conflict
    OPTIONAL { ?result rdfs:label ?resultLabel FILTER(LANG(?resultLabel) = "en") }
  }
}
ORDER BY ?conflict
